import React, { useCallback, useEffect, useState } from 'react';
import AssetTreePanel from './AssetTreePanel';
import AssetToolbar from './AssetToolbar';
import AssetTable from './AssetTable';
import AssetForm from './AssetForm';
import {
  Asset,
  AssetState,
  Product,
  ProductType,
  Vendor,
  deleteAsset,
  getAssetStates,
  getAssets,
  getProductTypes,
  getProducts,
  getVendors,
} from '../services/api';

type AssetPageMode = 'list' | 'create' | 'edit' | 'view';

const AssetsPage: React.FC = () => {
  const [selectedCategory, setSelectedCategory] = useState<string>('');
  const [selectedRows, setSelectedRows] = useState<string[]>([]);
  const [productTypes, setProductTypes] = useState<ProductType[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [assetStates, setAssetStates] = useState<AssetState[]>([]);
  const [loadingProductTypes, setLoadingProductTypes] = useState(false);
  const [loadingAssets, setLoadingAssets] = useState(false);
  const [productTypesError, setProductTypesError] = useState<string | null>(null);
  const [assetsError, setAssetsError] = useState<string | null>(null);
  const [mode, setMode] = useState<AssetPageMode>('list');
  const [editingAsset, setEditingAsset] = useState<Asset | null>(null);
  const [saving, setSaving] = useState(false);
  const selectedProductTypeName = productTypes.find((productType) => productType.id === selectedCategory)?.display_name || '';

  useEffect(() => {
    const fetchLookups = async () => {
      setLoadingProductTypes(true);
      setProductTypesError(null);

      try {
        const [productTypesResponse, productsResponse, vendorsResponse, assetStatesResponse] = await Promise.all([
          getProductTypes(),
          getProducts(),
          getVendors(),
          getAssetStates(),
        ]);

        setProductTypes(productTypesResponse.data);
        setProducts(productsResponse.data);
        setVendors(vendorsResponse.data);
        setAssetStates(assetStatesResponse.data);
      } catch (error) {
        console.error('Error fetching asset lookups:', error);
        setProductTypesError('Unable to load product types');
      } finally {
        setLoadingProductTypes(false);
      }
    };

    fetchLookups();
  }, []);

  const fetchAssets = useCallback(async () => {
    setLoadingAssets(true);
    setAssetsError(null);

    try {
      const response = await getAssets(selectedCategory);
      setAssets(response.data);
      setSelectedRows([]);
    } catch (error) {
      console.error('Error fetching assets:', error);
      setAssetsError('Unable to load assets');
    } finally {
      setLoadingAssets(false);
    }
  }, [selectedCategory]);

  useEffect(() => {
    fetchAssets();
  }, [fetchAssets]);

  const handleShowList = () => {
    setMode('list');
    setEditingAsset(null);
  };

  const handleSaveAsset = async () => {
    setSaving(true);
    try {
      await fetchAssets();
    } finally {
      setSaving(false);
    }
  };

  const handleDeleteSelected = async () => {
    if (selectedRows.length === 0) {
      return;
    }

    if (!window.confirm(`Delete ${selectedRows.length} selected asset${selectedRows.length > 1 ? 's' : ''}?`)) {
      return;
    }

    try {
      await Promise.all(selectedRows.map((id) => deleteAsset(id)));
      await fetchAssets();
    } catch (error) {
      console.error('Error deleting assets:', error);
    }
  };

  if (mode !== 'list') {
    return (
      <AssetForm
        editing={editingAsset}
        mode={mode}
        products={products}
        productTypes={productTypes}
        vendors={vendors}
        assetStates={assetStates}
        selectedProductTypeId={selectedCategory}
        saving={saving}
        onBack={handleShowList}
        onSave={handleSaveAsset}
      />
    );
  }

  return (
    <div>
      <div className="grid gap-6 xl:grid-cols-[250px_minmax(0,1fr)]">
        <AssetTreePanel
          productTypes={productTypes}
          selectedCategory={selectedCategory}
          onSelectCategory={setSelectedCategory}
          loading={loadingProductTypes}
          error={productTypesError}
        />

        <div className="space-y-5">
          <AssetToolbar
            selectedCount={selectedRows.length}
            showAddNew={Boolean(selectedCategory)}
            selectedProductTypeName={selectedProductTypeName}
            onAddNew={() => {
              setEditingAsset(null);
              setMode('create');
            }}
            onDeleteSelected={handleDeleteSelected}
            onClearFilters={() => {
              setSelectedCategory('');
            }}
            onSelectColumns={() => {
              // placeholder for Select Columns action
            }}
          />

          <AssetTable
            assets={assets}
            loading={loadingAssets}
            error={assetsError}
            selectedRows={selectedRows}
            onSelectedRowsChange={setSelectedRows}
            onView={(asset) => {
              setEditingAsset(asset);
              setMode('view');
            }}
            onEdit={(asset) => {
              setEditingAsset(asset);
              setMode('edit');
            }}
          />
        </div>
      </div>
    </div>
  );
};

export default AssetsPage;
